<?php use function App\Core\{e,url,csrf_field}; ?><section class="card"><h2>投稿文生成（一括対応）</h2><form method="post" action="<?= e(url('/posts/generate')) ?>"><?= csrf_field() ?><label>テンプレート<select name="template_id"><?php foreach($templates as $t): ?><option value="<?= $t['id'] ?>"><?= e($t['name']) ?></option><?php endforeach; ?></select></label><div class="checklist"><?php foreach($products as $p): ?><label><input type="checkbox" name="product_ids[]" value="<?= $p['id'] ?>"> <?= e($p['title']) ?></label><?php endforeach; ?></div><button class="primary">選択商品から投稿文を生成</button></form></section><section class="card"><h2>生成済み投稿</h2><button type="button" data-copy-all>すべてコピー</button><div class="posts"><?php foreach($posts as $p): ?><article class="post"><h3><?= e($p['title']) ?></h3><textarea readonly><?= e($p['body']) ?></textarea><button type="button" data-copy>コピー</button><form method="post" action="<?= e(url('/posts/delete')) ?>"><?= csrf_field() ?><input type="hidden" name="id" value="<?= $p['id'] ?>"><button>削除</button></form></article><?php endforeach; ?></div></section>
